package filters

import (
    "context"
    "fmt"

    "github.com/openmeterio/openmeter/openmeter/entitlement"
    "github.com/openmeterio/openmeter/pkg/models"
)

var _ NamedFilter = (*ArchivedFeatureFilter)(nil)

type ArchivedFeatureFilterConfig struct {
    EntitlementService entitlement.Service
}

func (c ArchivedFeatureFilterConfig) Validate() error {
    if c.EntitlementService == nil {
        return fmt.Errorf("entitlementService is required")
    }
    return nil
}

var _ models.Validator = ArchivedFeatureFilterConfig{}

type ArchivedFeatureFilter struct{ svc entitlement.Service }

func NewArchivedFeatureFilter(cfg ArchivedFeatureFilterConfig) (NamedFilter, error) {
    if err := cfg.Validate(); err != nil { return nil, err }
    return &ArchivedFeatureFilter{svc: cfg.EntitlementService}, nil
}

func (f *ArchivedFeatureFilter) Name() string { return "archived_feature" }

func (f *ArchivedFeatureFilter) IsNamespaceInScope(_ context.Context, _ string) (bool, error) {
    return true, nil
}

func (f *ArchivedFeatureFilter) IsEntitlementInScope(ctx context.Context, req EntitlementFilterRequest) (bool, error) {
    if err := req.Validate(); err != nil { return false, err }
    // ... check req.Entitlement.FeatureID against archived features ...
    return true, nil
}
